import{_ as n,C as o,o as r,c as t,a2 as i,E as s}from"./chunks/framework.BKG_UbFK.js";const k=JSON.parse('{"title":"Permessi","description":"","frontmatter":{},"headers":[],"relativePath":"it/features/permissions.md","filePath":"it/features/permissions.md"}'),l={name:"it/features/permissions.md"};function p(c,e,d,h,m,u){const a=o("Screenshot");return r(),t("div",null,[e[0]||(e[0]=i('<h1 id="permessi" tabindex="-1">Permessi <a class="header-anchor" href="#permessi" aria-label="Permalink to &quot;Permessi&quot;">​</a></h1><p>Il pannello Permessi è un&#39;interfaccia CRUD completa sul modello <code>Permission</code> di Spatie. Clearance non introduce mai una propria tabella dei permessi - ogni permesso creato qui è un normale permesso Spatie, utilizzabile ovunque venga usata l&#39;API di Spatie (<code>$user-&gt;can()</code>, <code>Gate::allows()</code>, policy, <code>@can</code>).</p><h2 id="cosa-fa-il-pannello" tabindex="-1">Cosa fa il pannello <a class="header-anchor" href="#cosa-fa-il-pannello" aria-label="Permalink to &quot;Cosa fa il pannello&quot;">​</a></h2><ul><li><strong>Creazione</strong> - aggiungi un nuovo permesso, validato rispetto alla <a href="#permission-naming-convention">convenzione di naming</a> (a meno che non sia disabilitata) e limitato a una guardia.</li><li><strong>Modifica</strong> - rinomina un permesso o cambia la sua guardia.</li><li><strong>Eliminazione</strong> - rimuovi un permesso e le sue assegnazioni a ruoli/utenti (comportamento standard di cascade di Spatie).</li></ul>',4)),s(a,{src:"/screenshots/permissions-page.png",alt:"Pannello Permessi di Clearance che elenca i permessi raggruppati per prefisso di naming",caption:"Il pannello Permessi elenca ogni permesso Spatie, raggruppato per prefisso di naming."}),s(a,{src:"/screenshots/permission-form-modal.png",alt:"Form di creazione/modifica permesso con validazione della convenzione di naming",caption:"Il form dei permessi valida la convenzione di naming group-action prima di salvare."}),e[1]||(e[1]=i(`<h2 id="convenzione-di-naming-dei-permessi" tabindex="-1">Convenzione di naming dei permessi <a class="header-anchor" href="#convenzione-di-naming-dei-permessi" aria-label="Permalink to &quot;Convenzione di naming dei permessi&quot;">​</a></h2><p>I permessi devono seguire il formato <code>group-action</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>orders-create       correct</span></span>
<span class="line"><span>orders-read         correct</span></span>
<span class="line"><span>store-orders-delete correct</span></span>
<span class="line"><span></span></span>
<span class="line"><span>create              wrong (bare action, no group)</span></span>
<span class="line"><span>orders.create       wrong (dot separator)</span></span>
<span class="line"><span>Orders-Create       wrong (camelCase)</span></span></code></pre></div><p>Il prefisso di gruppo (<code>orders</code> in <code>orders-create</code>) è ciò che la <a href="/clearance-docs/it/features/dashboard.html">Dashboard</a> usa per contare i gruppi di permessi distinti.</p><div class="tip custom-block"><p class="custom-block-title">Disabilitare l&#39;applicazione</p><p>Alcuni team migrano da uno schema di naming diverso. Disabilita il controllo per ambiente:</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// config/clearance.php</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;enforce_naming_convention&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> false</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span></code></pre></div></div><h2 id="controllo-degli-accessi" tabindex="-1">Controllo degli accessi <a class="header-anchor" href="#controllo-degli-accessi" aria-label="Permalink to &quot;Controllo degli accessi&quot;">​</a></h2><p>L&#39;accesso in lettura al pannello (visualizzazione dell&#39;elenco dei permessi) richiede <code>clearance-access</code>. Creare, modificare, o eliminare un permesso richiede inoltre <code>clearance-permissions-write</code>:</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$user</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">givePermissionTo</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;clearance-access&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$user</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">givePermissionTo</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;clearance-permissions-write&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">I permessi <code>clearance-*</code> sono riservati</p><p>I permessi <code>clearance-*</code> stessi (<code>clearance-access</code>, <code>clearance-permissions-write</code>, ecc.) non possono essere creati, rinominati, o eliminati tramite questo pannello - nemmeno da un attore <code>super_admin</code>. Sono gestiti esclusivamente dal flusso di installazione proprio del pacchetto. Vedi <a href="/clearance-docs/it/features/super-admin.html#reserved-clearance-permissions">Super Admin</a>.</p></div><h2 id="route-e-componente-incorporato" tabindex="-1">Route e componente incorporato <a class="header-anchor" href="#route-e-componente-incorporato" aria-label="Permalink to &quot;Route e componente incorporato&quot;">​</a></h2><table tabindex="0"><thead><tr><th>URI</th><th>Nome route</th><th>Descrizione</th></tr></thead><tbody><tr><td><code>/clearance/permissions</code></td><td><code>clearance.permissions</code></td><td>CRUD permessi con validazione del naming a prefisso di gruppo</td></tr></tbody></table><div class="language-blade vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">blade</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#B31D28;--shiki-light-font-style:italic;--shiki-dark:#FDAEB7;--shiki-dark-font-style:italic;">livewire:clearance::permissions.permission-manager</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /&gt;</span></span></code></pre></div><h2 id="prossimi-passi" tabindex="-1">Prossimi passi <a class="header-anchor" href="#prossimi-passi" aria-label="Permalink to &quot;Prossimi passi&quot;">​</a></h2><ul><li><a href="/clearance-docs/it/features/roles.html">Ruoli</a> - assegna permessi a un ruolo, limitati alla guardia.</li><li><a href="/clearance-docs/it/features/super-admin.html">Super Admin</a> - la tabella completa dei permessi di scrittura granulari.</li><li><a href="/clearance-docs/it/guide/configuration.html">Riferimento di configurazione</a> - <code>enforce_naming_convention</code>, <code>naming_separator</code>.</li></ul>`,14))])}const v=n(l,[["render",p]]);export{k as __pageData,v as default};
